import{_ as a,o,c as t,ag as i}from"./chunks/framework.DTiDeF2Q.js";const p=JSON.parse('{"title":"About Dotfiles | Dotfiles (EN)","titleTemplate":":title","description":"Learn how Dotfiles v0.2.495 delivers security-first shell configuration with Chezmoi, 1,200+ aliases, and Rust-powered CLI tools for macOS, Linux, and WSL.","frontmatter":{"title":"About Dotfiles | Dotfiles","description":"Learn how Dotfiles v0.2.495 delivers security-first shell configuration with Chezmoi, 1,200+ aliases, and Rust-powered CLI tools for macOS, Linux, and WSL.","lang":"en-GB","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"About Dotfiles | Dotfiles preview","canonical":"/en/about/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"About Dotfiles","pageType":"docs","schemaType":"WebPage","permalink":"/en/about/"},"headers":[],"relativePath":"en/about/index.md","filePath":"en/about/index.md","lastUpdated":1773010926000}'),s={name:"en/about/index.md"};function l(d,e,c,r,n,h){return o(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="about-dotfiles" tabindex="-1">About Dotfiles <a class="header-anchor" href="#about-dotfiles" aria-label="Permalink to &quot;About Dotfiles&quot;">​</a></h1><p>Dotfiles v0.2.495 is a cross-platform shell configuration framework managed by Chezmoi, providing security-first defaults for Bash, Zsh, and Fish across macOS, Linux, and WSL2. It bundles over 1 200 aliases, modern Rust-based CLI replacements, and automated secret management so developers can set up a fully configured terminal environment in minutes.</p><h2 id="install" tabindex="-1">Install <a class="header-anchor" href="#install" aria-label="Permalink to &quot;Install&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://raw.githubusercontent.com/sebastienrousseau/dotfiles/master/install.sh)&quot;</span></span></code></pre></div><h2 id="verify" tabindex="-1">Verify <a class="header-anchor" href="#verify" aria-label="Permalink to &quot;Verify&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> doctor</span></span></code></pre></div><h2 id="core-commands" tabindex="-1">Core commands <a class="header-anchor" href="#core-commands" aria-label="Permalink to &quot;Core commands&quot;">​</a></h2><p>The <code>dot</code> CLI exposes 53 commands organised by category.</p><h3 id="core" tabindex="-1">Core <a class="header-anchor" href="#core" aria-label="Permalink to &quot;Core&quot;">​</a></h3><ul><li><code>dot apply</code> — applies configuration changes.</li><li><code>dot sync</code> — pulls the latest repo state and applies.</li><li><code>dot update</code> — updates the repo and warms caches.</li><li><code>dot add</code> — stages new files into Chezmoi source.</li><li><code>dot diff</code> — shows pending changes before apply.</li><li><code>dot status</code> — displays managed-file status.</li><li><code>dot remove</code> — un-manages a file and removes the source entry.</li><li><code>dot cd</code> — opens a shell inside the Chezmoi source directory.</li><li><code>dot edit</code> — opens a managed file in your editor.</li><li><code>dot clean-cache</code> — purges transient caches.</li><li><code>dot prewarm</code> — pre-populates caches for faster shell startup.</li></ul><h3 id="diagnostics" tabindex="-1">Diagnostics <a class="header-anchor" href="#diagnostics" aria-label="Permalink to &quot;Diagnostics&quot;">​</a></h3><ul><li><code>dot doctor</code> — validates paths, tools, and shell health.</li><li><code>dot heal</code> — repairs missing or broken state automatically.</li><li><code>dot health</code> — runs a lightweight health probe.</li><li><code>dot verify</code> — checks file integrity against source.</li><li><code>dot scorecard</code> — prints a configuration quality score.</li><li><code>dot snapshot</code> — captures current state for later comparison.</li><li><code>dot smoke-test</code> — validates core toolchains end-to-end.</li><li><code>dot chaos</code> — injects faults to test self-healing.</li><li><code>dot bundle</code> — exports a portable configuration bundle.</li><li><code>dot rollback</code> — reverts to a previous snapshot.</li><li><code>dot drift</code> — detects out-of-band changes to managed files.</li><li><code>dot history</code> — shows the apply/sync history log.</li><li><code>dot benchmark</code> — measures shell startup time.</li><li><code>dot perf</code> — profiles slow shell initialisation.</li></ul><h3 id="appearance" tabindex="-1">Appearance <a class="header-anchor" href="#appearance" aria-label="Permalink to &quot;Appearance&quot;">​</a></h3><ul><li><code>dot theme</code> — switches the terminal colour scheme.</li><li><code>dot wallpaper</code> — sets the desktop wallpaper (macOS).</li><li><code>dot fonts</code> — installs or updates Nerd Fonts.</li><li><code>dot tune</code> — adjusts UI density and prompt style.</li></ul><h3 id="security" tabindex="-1">Security <a class="header-anchor" href="#security" aria-label="Permalink to &quot;Security&quot;">​</a></h3><ul><li><code>dot backup</code> — creates encrypted configuration backups.</li><li><code>dot encrypt-check</code> — verifies secret encryption at rest.</li><li><code>dot firewall</code> — configures host firewall rules.</li><li><code>dot telemetry</code> — controls anonymous usage telemetry.</li><li><code>dot dns-doh</code> — enables DNS-over-HTTPS.</li><li><code>dot lock-screen</code> — locks the screen immediately.</li><li><code>dot usb-safety</code> — restricts USB mass-storage auto-mount.</li></ul><h3 id="secrets" tabindex="-1">Secrets <a class="header-anchor" href="#secrets" aria-label="Permalink to &quot;Secrets&quot;">​</a></h3><ul><li><code>dot secrets-init</code> — bootstraps the secrets backend (age / GPG).</li><li><code>dot secrets</code> — lists encrypted secret entries.</li><li><code>dot secrets-create</code> — creates a new encrypted secret.</li><li><code>dot ssh-key</code> — generates or rotates SSH key pairs.</li><li><code>dot ssh-cert</code> — requests an SSH certificate from a CA.</li></ul><h3 id="ai" tabindex="-1">AI <a class="header-anchor" href="#ai" aria-label="Permalink to &quot;AI&quot;">​</a></h3><ul><li><code>dot ai</code> — opens an interactive AI assistant session.</li><li><code>dot ai-setup</code> — configures API keys for AI providers.</li><li><code>dot ai-query</code> — sends a one-shot prompt to an AI model.</li><li>AI-tool wrappers: <code>cl</code>, <code>gemini</code>, <code>kiro</code>, <code>sgpt</code>, <code>ollama</code>, <code>opencode</code>, <code>aider</code>.</li></ul><h3 id="tools" tabindex="-1">Tools <a class="header-anchor" href="#tools" aria-label="Permalink to &quot;Tools&quot;">​</a></h3><ul><li><code>dot tools</code> — lists bundled CLI replacements and their status.</li><li><code>dot new</code> — scaffolds a new alias or function file.</li><li><code>dot sandbox</code> — opens a disposable sandbox shell.</li><li><code>dot keys</code> — shows current key bindings.</li><li><code>dot learn</code> — starts the interactive tutorial.</li></ul><h3 id="meta" tabindex="-1">Meta <a class="header-anchor" href="#meta" aria-label="Permalink to &quot;Meta&quot;">​</a></h3><ul><li><code>dot upgrade</code> — upgrades Dotfiles to the latest release.</li><li><code>dot packages</code> — lists installed packages managed by Dotfiles.</li><li><code>dot version</code> / <code>dot help</code> — prints version or usage information.</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/en/aliases/">Aliases</a></li><li><a href="/en/functions/">Functions</a></li><li><a href="/en/paths/">Paths</a></li><li><a href="/en/compatibility/">Compatibility Matrix</a></li></ul>',26)])])}const f=a(s,[["render",l]]);export{p as __pageData,f as default};
